const response = $input.item.json;
const raw = response.content[0].text;

// Strip markdown code fences Claude sometimes adds
const cleaned = raw
  .replace(/```json\n?/g, '')
  .replace(/```\n?/g, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = { error: "Could not parse", raw: cleaned };
}

return {
  json: {
    from: $input.item.json.from || "unknown",
    subject: $input.item.json.subject || "unknown",
    ...parsed
  }
};
